-- =============================================================
-- FILE: 131_bereketfide_storage_assets.seed.sql
-- Bereket Fide — Local Storage Assets (uploads/)
-- =============================================================

SET NAMES utf8mb4;
SET time_zone = '+00:00';
SET FOREIGN_KEY_CHECKS = 0;

START TRANSACTION;

-- =========================
-- STATIC IMAGES
-- =========================
ON DUPLICATE KEY UPDATE
  url = VALUES(url),
  size = VALUES(size),
  updated_at = NOW();

COMMIT;
SET FOREIGN_KEY_CHECKS = 1;
